import type { Model, Provider } from "@opencode-ai/sdk/v2"
import { Log } from "../util"

const log = Log.create({ service: "plugin.openai-models-discovery" })

type Options = {
  providerID?: string
  providerName?: string
  baseURL?: string
  apiKeyEnv?: string
  defaults?: {
    context?: number
    output?: number
    reasoning?: boolean
    toolcall?: boolean
    attachment?: boolean
    temperature?: boolean
  }
}

type OpenAIModelEntry = {
  id: string
  object?: string
  created?: number
  owned_by?: string
}

type OpenAIModelsResponse = {
  object: string
  data: OpenAIModelEntry[]
}

function inferCapabilities(modelId: string, defaults?: Options["defaults"]) {
  const id = modelId.toLowerCase()
  const reasoning = defaults?.reasoning ?? (id.includes("o1") || id.includes("o3") || id.includes("o4"))
  const toolcall = defaults?.toolcall ?? !reasoning
  const attachment = defaults?.attachment ?? (id.includes("gpt-4") || id.includes("gpt-5"))
  const temperature = defaults?.temperature ?? !reasoning

  return {
    temperature,
    reasoning,
    attachment,
    toolcall,
    input: {
      text: true,
      audio: false,
      image: attachment,
      video: false,
      pdf: false,
    },
    output: {
      text: true,
      audio: false,
      image: false,
      video: false,
      pdf: false,
    },
    interleaved: false as const,
  }
}

function buildModel(entry: OpenAIModelEntry, providerID: string, baseURL: string, opts: Options): Model {
  return {
    id: entry.id,
    providerID,
    api: {
      id: entry.id,
      url: baseURL,
      npm: "@ai-sdk/openai-compatible",
    },
    name: entry.id,
    capabilities: inferCapabilities(entry.id, opts.defaults),
    cost: {
      input: 0,
      output: 0,
      cache: { read: 0, write: 0 },
    },
    limit: {
      context: opts.defaults?.context ?? 128000,
      output: opts.defaults?.output ?? 16384,
    },
    status: "active",
    options: {},
    headers: {},
    release_date: entry.created ? new Date(entry.created * 1000).toISOString().split("T")[0] : "",
  }
}

async function fetchModels(baseURL: string, apiKey: string): Promise<OpenAIModelEntry[]> {
  const url = `${baseURL.replace(/\/$/, "")}/models`
  log.info("fetching models", { url })

  const res = await fetch(url, {
    headers: { Authorization: `Bearer ${apiKey}` },
  }).catch((e) => {
    log.error("failed to fetch models", { error: e })
    return undefined
  })

  if (!res || !res.ok) {
    log.warn("models endpoint returned non-ok", { status: res?.status })
    return []
  }

  const body: OpenAIModelsResponse = await res.json()
  return body.data.filter((entry) => !entry.object || entry.object === "model")
}

export async function OpenAIModelsDiscoveryPlugin(_input: PluginInput, options?: PluginOptions): Promise<Hooks> {
  const opts = (options ?? {}) as Options
  const providerID = opts.providerID ?? "openai-compatible"
  const providerName = opts.providerName ?? "OpenAI Compatible"
  const baseURL = opts.baseURL ?? ""

  return {
    async config(config: Config) {
      if (!config.provider) config.provider = {}
      if (config.provider[providerID]) return

      config.provider[providerID] = {
        name: providerName,
        npm: "@ai-sdk/openai-compatible",
        ...(baseURL && { api: baseURL }),
        ...(opts.apiKeyEnv && { env: [opts.apiKeyEnv] }),
      }
    },

    auth: {
      provider: providerID,
      methods: [
        {
          type: "api",
          label: "API Key",
          prompts: [
            ...(baseURL
              ? []
              : [
                  {
                    type: "text" as const,
                    key: "baseURL",
                    message: "Enter the base URL (OpenAI-compatible /v1 endpoint)",
                    placeholder: "e.g. http://localhost:11434/v1 or https://api.openai.com/v1",
                  },
                ]),
          ],
          async authorize(inputs) {
            const url = inputs?.baseURL || baseURL
            if (!url) return { type: "failed" as const }
            return { type: "success" as const, key: "", provider: providerID }
          },
        },
      ],
      async loader(getAuth) {
        const auth = await getAuth()
        if (!auth) return {}
        const resolvedURL = (auth as any).baseURL || baseURL
        return {
          ...(resolvedURL && { baseURL: resolvedURL }),
        }
      },
    },

    provider: {
      id: providerID,
      async models(provider: Provider, ctx) {
        const apiKey = ctx.auth?.key ?? provider.key ?? (opts.apiKeyEnv ? process.env[opts.apiKeyEnv] : undefined)
        const resolvedURL = (provider.options?.baseURL as string) || baseURL

        if (!resolvedURL) {
          log.warn("no base URL configured, skipping model discovery")
          return provider.models as Record<string, Model>
        }

        if (!apiKey) {
          log.warn("no api key available, skipping model discovery")
          return provider.models as Record<string, Model>
        }

        const entries = await fetchModels(resolvedURL, apiKey)
        if (entries.length === 0) return provider.models as Record<string, Model>

        const models: Record<string, Model> = {}
        for (const entry of entries) {
          models[entry.id] = buildModel(entry, provider.id, resolvedURL, opts)
        }

        log.info("discovered models", { count: Object.keys(models).length })
        return models
      },
    },
  }
}

